<template><section class="page"><header><div><h2>Invocation History</h2><p>Saved model calls from this browser.</p></div><button @click="clear">Clear Invocation History</button></header><div class="filters"><select v-model="status"><option value="">All statuses</option><option>succeeded</option><option>failed</option><option>cancelled</option></select><input v-model="provider" placeholder="Provider"><button @click="load">Filter</button></div><div v-if="error" class="error">{{error}}</div><div v-else-if="!items.length" class="empty">No invocations found.</div><table v-else><thead><tr><th>Prompt</th><th>Version</th><th>Model</th><th>Status</th><th>Latency</th><th>Tokens</th><th>Created</th></tr></thead><tbody><tr v-for="item in items" :key="item.id" @click="$router.push(`/invocations/${item.id}`)"><td>{{item.promptName}}</td><td>{{item.promptVersionNumber||'—'}}</td><td>{{item.provider}} / {{item.modelName}}</td><td>{{item.status}}</td><td>{{item.latencyMs??'—'}} ms</td><td>{{item.tokenUsage.totalTokens??'Unavailable'}}</td><td>{{item.createdAt}}</td></tr></tbody></table><button v-if="items.length<total" @click="more">Load more</button></section></template>
<script setup lang="ts">import{onMounted,ref}from'vue';import type{InvocationStatus,ModelInvocation}from'@prompt-optimizer/core';import{usePromptOpsServices}from'../../services/promptops';import{usePromptOpsUiStore}from'../../stores/promptops/usePromptOpsUiStore';const services=usePromptOpsServices(),store=usePromptOpsUiStore(),items=ref<ModelInvocation[]>([]),total=ref(0),status=ref(''),provider=ref(''),error=ref('');const query=()=>({workspaceId:store.currentWorkspaceId,status:(status.value||undefined)as InvocationStatus|undefined,provider:provider.value||undefined});const load=async()=>{try{const result=await services.invocationRepository.list({...query(),limit:20});items.value=result.items;total.value=result.total}catch(e){error.value=e instanceof Error?e.message:String(e)}};const more=async()=>{const result=await services.invocationRepository.list({...query(),limit:20,offset:items.value.length});items.value.push(...result.items)};const clear=async()=>{if(confirm('Clear invocation history? Prompts and versions will not be removed.')){await services.invocationRepository.clear();await load()}};onMounted(load)</script>
<style scoped>.page{display:grid;gap:16px}header{display:flex;justify-content:space-between}h2{margin:0}.filters{display:flex;gap:8px}.filters>*{padding:8px;border:1px solid #cbd5e1;border-radius:7px}table{width:100%;border-collapse:collapse;background:#fff;border:1px solid #e5e7eb}th,td{text-align:left;padding:12px;border-bottom:1px solid #e5e7eb}tbody tr{cursor:pointer}.empty{padding:60px;text-align:center;background:#fff}.error{color:#b91c1c}button{padding:8px 12px;border:1px solid #cbd5e1;background:#fff;border-radius:7px;cursor:pointer}</style>
